#define THREADS_PER_BLOCK 256
#define MAXBLOCKS 65536

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

kernel void pgain_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    int num,
    int dim,
    long x,
    int K
) {
    int i = get_global_id(0);
    if (i >= num) return;

    // Calculate distance from point i to point x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - coord[x * dim + d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int center_idx = center_table[assign];
        work_mem[i * (K + 1) + center_idx] += current_cost - x_cost;
    }
}

kernel void init_centers_kernel(
    global int* center_table,
    global char* is_center,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i]) {
        center_table[i] = i;
    }
}

kernel void copy_coord_kernel(
    global float* coord_d,
    global float* coord_h,
    int num,
    int dim
) {
    int idx = get_global_id(0);
    if (idx >= num * dim) return;
    coord_d[idx] = coord_h[idx];
}

kernel void copy_p_kernel(
    global Point_Struct* p_d,
    global Point_Struct* p_h,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    p_d[i] = p_h[i];
}

kernel void copy_center_table_kernel(
    global int* center_table_d,
    global int* center_table_h,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    center_table_d[i] = center_table_h[i];
}

kernel void memset_kernel(
    global void* dest,
    unsigned char value,
    int size
) {
    int i = get_global_id(0);
    if (i >= size) return;
    ((global unsigned char*)dest)[i] = value;
}
